export type RunState = "starting" | "running" | "exiting" | "exited";

export type TerminationReason =
  | "manual-cancel"
  | "overall-timeout"
  | "no-output-timeout"
  | "spawn-error"
  | "signal"
  | "exit";

export type RunRecord = {
  runId: string;
  pid?: number;
  state: RunState;
  startedAtMs: number;
  lastOutputAtMs: number;
  terminationReason?: TerminationReason;
  exitCode: number | null;
